from __future__ import annotations

from pathlib import Path

from meta_controller.core.models import WorkerResult
from meta_controller.workers.base import RoleWorker


class FullstackBuilderWorker(RoleWorker):
    role = "fullstack_builder"
    objective = "create or update a runnable fullstack prototype with frontend, backend, storage, and startup scripts"
    output_fields = ["patch_plan", "changed_files", "implementation_notes"]

    def run(self, task_spec, upstream_results, memory_refs=None) -> WorkerResult:
        project_path = Path(task_spec.project_path or ".")
        app_kind = self._detect_app_kind(task_spec.user_text)
        if app_kind in {"log", "todo", "notes"}:
            changed_files = self._build_python_prototype(project_path=project_path, app_kind=app_kind)
            return WorkerResult(
                status="success",
                summary=f"generated a runnable {app_kind} app prototype",
                artifacts=changed_files,
                structured_output={
                    "patch_plan": f"generated Flask + SQLite + static frontend prototype for {app_kind} use case",
                    "changed_files": changed_files,
                    "implementation_notes": (
                        f"{app_kind} prototype scaffolded deterministically from the task intent. "
                        "Includes backend routes, local persistence, static frontend, tests, and README."
                    ),
                },
                cost=0.0,
                token_usage={"input_tokens": 0, "output_tokens": 0},
                tool_trace=[{"tool": "local_builder", "app_kind": app_kind, "runtime": "builder", "node_id": self.node.id}],
                confidence=0.98,
                failure_type=None,
            )

        return super().run(task_spec=task_spec, upstream_results=upstream_results, memory_refs=memory_refs)

    def _detect_app_kind(self, text: str) -> str:
        lower = text.lower()
        if "log" in lower:
            return "log"
        if "todo" in lower or "task" in lower:
            return "todo"
        if "note" in lower:
            return "notes"
        if "expense" in lower:
            return "expense"
        if "bookmark" in lower:
            return "bookmark"
        if "inventory" in lower:
            return "inventory"
        return "generic"

    def _build_python_prototype(self, project_path: Path, app_kind: str) -> list[str]:
        (project_path / "templates").mkdir(parents=True, exist_ok=True)
        (project_path / "static").mkdir(parents=True, exist_ok=True)
        (project_path / "tests").mkdir(parents=True, exist_ok=True)
        files = self._prototype_files(app_kind)
        changed: list[str] = []
        for relative_path, content in files.items():
            target = project_path / relative_path
            target.parent.mkdir(parents=True, exist_ok=True)
            target.write_text(content, encoding="utf-8")
            changed.append(relative_path)
        return changed

    def _prototype_files(self, app_kind: str) -> dict[str, str]:
        if app_kind == "log":
            return self._log_files()
        if app_kind == "todo":
            return self._todo_files()
        if app_kind == "expense":
            return self._expense_files()
        if app_kind == "bookmark":
            return self._bookmark_files()
        if app_kind == "inventory":
            return self._inventory_files()
        return self._notes_files()

    def _shared_requirements(self) -> str:
        return "flask==3.1.1\npytest==8.4.2\n"

    def _log_files(self) -> dict[str, str]:
        return {
            "requirements.txt": self._shared_requirements(),
            "db.py": """import os\nimport sqlite3\nfrom datetime import datetime, timezone\n\nDB_PATH = os.environ.get('LOG_DB_PATH', 'logs.db')\nVALID_LEVELS = ('DEBUG', 'INFO', 'WARNING', 'ERROR', 'CRITICAL')\n\n\ndef get_connection(db_path=None):\n    conn = sqlite3.connect(db_path or DB_PATH)\n    conn.row_factory = sqlite3.Row\n    conn.execute('PRAGMA journal_mode=WAL')\n    return conn\n\n\ndef init_db(db_path=None):\n    conn = get_connection(db_path)\n    conn.executescript('''\n    CREATE TABLE IF NOT EXISTS logs (\n        id INTEGER PRIMARY KEY AUTOINCREMENT,\n        message TEXT NOT NULL,\n        level TEXT NOT NULL,\n        source TEXT NOT NULL DEFAULT 'user',\n        timestamp TEXT NOT NULL\n    );\n    CREATE INDEX IF NOT EXISTS idx_logs_level ON logs(level);\n    CREATE INDEX IF NOT EXISTS idx_logs_timestamp ON logs(timestamp DESC);\n    ''')\n    conn.commit(); conn.close()\n\n\ndef create_log(message, level, source='user', db_path=None):\n    conn = get_connection(db_path)\n    ts = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')\n    cur = conn.execute('INSERT INTO logs (message, level, source, timestamp) VALUES (?, ?, ?, ?)', (message, level, source, ts))\n    conn.commit()\n    row = conn.execute('SELECT * FROM logs WHERE id = ?', (cur.lastrowid,)).fetchone()\n    conn.close()\n    return dict(row)\n\n\ndef search_logs(q=None, level=None, db_path=None):\n    conn = get_connection(db_path)\n    clauses = []\n    params = []\n    if q:\n        clauses.append('(message LIKE ? OR source LIKE ?)')\n        like = f'%{q}%'\n        params.extend([like, like])\n    if level:\n        clauses.append('level = ?')\n        params.append(level)\n    where = ' AND '.join(clauses) if clauses else '1=1'\n    rows = conn.execute(f'SELECT * FROM logs WHERE {where} ORDER BY timestamp DESC', params).fetchall()\n    conn.close()\n    return [dict(r) for r in rows]\n\n\ndef get_log(log_id, db_path=None):\n    conn = get_connection(db_path)\n    row = conn.execute('SELECT * FROM logs WHERE id = ?', (log_id,)).fetchone()\n    conn.close()\n    return dict(row) if row else None\n""",
            "app.py": """import os\nfrom flask import Flask, jsonify, render_template, request\nfrom db import VALID_LEVELS, create_log, get_log, init_db, search_logs\n\napp = Flask(__name__)\nDB_PATH = os.environ.get('LOG_DB_PATH', 'logs.db')\n\nwith app.app_context():\n    init_db(DB_PATH)\n\n@app.route('/')\ndef index():\n    return render_template('index.html')\n\n@app.route('/health')\ndef health():\n    return jsonify({'status': 'ok'})\n\n@app.route('/api/levels')\ndef levels():\n    return jsonify(list(VALID_LEVELS))\n\n@app.route('/api/logs', methods=['GET'])\ndef list_logs():\n    q = request.args.get('q')\n    level = request.args.get('level')\n    if level and level not in VALID_LEVELS:\n        return jsonify({'error': 'invalid level'}), 400\n    return jsonify({'logs': search_logs(q=q, level=level, db_path=DB_PATH)})\n\n@app.route('/api/logs', methods=['POST'])\ndef add_log():\n    data = request.get_json(silent=True) or {}\n    message = (data.get('message') or '').strip()\n    level = (data.get('level') or 'INFO').upper()\n    source = (data.get('source') or 'user').strip() or 'user'\n    if not message:\n        return jsonify({'error': 'message is required'}), 400\n    if level not in VALID_LEVELS:\n        return jsonify({'error': 'invalid level'}), 400\n    return jsonify(create_log(message, level, source, DB_PATH)), 201\n\n@app.route('/api/logs/<int:log_id>')\ndef detail(log_id):\n    row = get_log(log_id, DB_PATH)\n    if not row:\n        return jsonify({'error': 'not found'}), 404\n    return jsonify(row)\n\nif __name__ == '__main__':\n    port = int(os.environ.get('PORT', '5000'))\n    app.run(host='0.0.0.0', port=port, debug=False)\n""",
            "templates/index.html": """<!doctype html>\n<html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Local Log App</title><link rel='stylesheet' href='/static/style.css'></head><body><main class='container'><h1>Local Log App</h1><section class='panel'><h2>Create Log</h2><form id='log-form'><textarea id='message' placeholder='Log message' required></textarea><div class='row'><select id='level'><option>DEBUG</option><option selected>INFO</option><option>WARNING</option><option>ERROR</option><option>CRITICAL</option></select><input id='source' placeholder='source'></div><button type='submit'>Add Log</button></form></section><section class='panel'><h2>Logs</h2><div class='row'><input id='search' placeholder='Search keyword'><select id='filter-level'><option value=''>All levels</option><option>DEBUG</option><option>INFO</option><option>WARNING</option><option>ERROR</option><option>CRITICAL</option></select><button id='refresh'>Refresh</button></div><div id='logs'></div></section></main><script src='/static/app.js'></script></body></html>\n""",
            "static/app.js": """const $ = (s) => document.querySelector(s);\nasync function loadLogs() {\n  const q = $('#search').value.trim();\n  const level = $('#filter-level').value;\n  const params = new URLSearchParams();\n  if (q) params.set('q', q);\n  if (level) params.set('level', level);\n  const res = await fetch('/api/logs?' + params.toString());\n  const data = await res.json();\n  const target = $('#logs');\n  target.innerHTML = (data.logs || []).map(log => `<article class=\"log\"><div class=\"meta\"><strong>${log.level}</strong> <span>${log.timestamp}</span> <span>${log.source}</span></div><p>${log.message}</p></article>`).join('') || '<p class=\"empty\">No logs yet.</p>';\n}\n$('#log-form').addEventListener('submit', async (e) => {\n  e.preventDefault();\n  await fetch('/api/logs', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({message: $('#message').value.trim(), level: $('#level').value, source: $('#source').value.trim()})});\n  $('#message').value = ''; $('#source').value = ''; loadLogs();\n});\n$('#refresh').addEventListener('click', loadLogs);\n$('#search').addEventListener('keydown', (e) => { if (e.key === 'Enter') loadLogs(); });\n$('#filter-level').addEventListener('change', loadLogs);\nloadLogs();\n""",
            "static/style.css": """body{font-family:Arial,sans-serif;background:#f3f4f6;margin:0}.container{max-width:900px;margin:0 auto;padding:24px}.panel{background:#fff;padding:16px;border-radius:10px;margin-bottom:16px;box-shadow:0 1px 4px rgba(0,0,0,.08)}.row{display:flex;gap:8px;flex-wrap:wrap}textarea,input,select,button{font:inherit;padding:10px;border-radius:8px;border:1px solid #cbd5e1}textarea,input{width:100%}button{background:#2563eb;color:#fff;border:none;cursor:pointer}.log{border-top:1px solid #e5e7eb;padding:10px 0}.meta{display:flex;gap:12px;font-size:.9rem;color:#475569}.empty{color:#64748b}""",
            "README.md": """# Local Log App\n\nA local log app built with Flask, SQLite, and a lightweight frontend.\n\n## Run\n```bash\ncd .\npython3 -m venv .venv\nsource .venv/bin/activate\npip install -r requirements.txt\npython app.py\n```\nOpen http://localhost:5000\n\n## Test\n```bash\nsource .venv/bin/activate\npytest tests -q\n```\n""",
            "tests/test_api.py": """import os\nimport tempfile\n\n_tmp = tempfile.NamedTemporaryFile(suffix='.db', delete=False)\n_tmp.close()\nos.environ['LOG_DB_PATH'] = _tmp.name\n\nfrom app import app\n\n\ndef test_health(client=None):\n    app.config['TESTING'] = True\n    with app.test_client() as c:\n        assert c.get('/health').status_code == 200\n        assert c.post('/api/logs', json={'message': 'hello', 'level': 'INFO'}).status_code == 201\n        data = c.get('/api/logs').get_json()\n        assert data['logs']\n        assert c.get('/api/logs?level=INFO').status_code == 200\n""",
            "run.sh": "#!/usr/bin/env bash\npython3 -m venv .venv\nsource .venv/bin/activate\npip install -r requirements.txt\npython app.py\n",
        }

    def _todo_files(self) -> dict[str, str]:
        return {
            "requirements.txt": self._shared_requirements(),
            "app.py": """import os\nimport sqlite3\nfrom flask import Flask, jsonify, request, send_from_directory\n\napp = Flask(__name__, static_folder='static')\nDATABASE = os.environ.get('TODO_DB', 'todos.db')\n\n\ndef get_db():\n    conn = sqlite3.connect(DATABASE)\n    conn.row_factory = sqlite3.Row\n    return conn\n\n\ndef init_db():\n    conn = get_db()\n    conn.execute('CREATE TABLE IF NOT EXISTS tasks (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, completed INTEGER NOT NULL DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)')\n    conn.commit(); conn.close()\n\nwith app.app_context():\n    init_db()\n\n@app.route('/')\ndef index():\n    return send_from_directory(app.static_folder, 'index.html')\n\n@app.route('/health')\ndef health():\n    return jsonify({'status': 'ok'})\n\n@app.route('/api/tasks', methods=['GET'])\ndef list_tasks():\n    status = request.args.get('status', 'all')\n    conn = get_db()\n    query = 'SELECT * FROM tasks ORDER BY created_at DESC'\n    if status == 'active': query = 'SELECT * FROM tasks WHERE completed = 0 ORDER BY created_at DESC'\n    if status == 'completed': query = 'SELECT * FROM tasks WHERE completed = 1 ORDER BY created_at DESC'\n    rows = conn.execute(query).fetchall(); conn.close()\n    return jsonify([{'id': r['id'], 'title': r['title'], 'completed': bool(r['completed'])} for r in rows])\n\n@app.route('/api/tasks', methods=['POST'])\ndef create_task():\n    data = request.get_json(silent=True) or {}\n    title = (data.get('title') or '').strip()\n    if not title: return jsonify({'error': 'title is required'}), 400\n    conn = get_db(); cur = conn.execute('INSERT INTO tasks (title) VALUES (?)', (title,)); conn.commit(); row = conn.execute('SELECT * FROM tasks WHERE id = ?', (cur.lastrowid,)).fetchone(); conn.close()\n    return jsonify({'id': row['id'], 'title': row['title'], 'completed': bool(row['completed'])}), 201\n\n@app.route('/api/tasks/<int:task_id>', methods=['PATCH'])\ndef update_task(task_id):\n    data = request.get_json(silent=True) or {}\n    if 'completed' not in data: return jsonify({'error': 'completed field is required'}), 400\n    conn = get_db(); row = conn.execute('SELECT * FROM tasks WHERE id = ?', (task_id,)).fetchone()\n    if row is None: conn.close(); return jsonify({'error': 'task not found'}), 404\n    conn.execute('UPDATE tasks SET completed = ? WHERE id = ?', (1 if data['completed'] else 0, task_id)); conn.commit(); row = conn.execute('SELECT * FROM tasks WHERE id = ?', (task_id,)).fetchone(); conn.close()\n    return jsonify({'id': row['id'], 'title': row['title'], 'completed': bool(row['completed'])})\n\n@app.route('/api/tasks/<int:task_id>', methods=['DELETE'])\ndef delete_task(task_id):\n    conn = get_db(); row = conn.execute('SELECT * FROM tasks WHERE id = ?', (task_id,)).fetchone()\n    if row is None: conn.close(); return jsonify({'error': 'task not found'}), 404\n    conn.execute('DELETE FROM tasks WHERE id = ?', (task_id,)); conn.commit(); conn.close(); return '', 204\n\nif __name__ == '__main__':\n    app.run(host='0.0.0.0', port=int(os.environ.get('PORT', '5000')), debug=False)\n""",
            "static/index.html": """<!doctype html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Todo App</title><link rel='stylesheet' href='/static/style.css'></head><body><div class='container'><h1>Todo App</h1><form id='task-form' class='task-input'><input id='task-title' type='text' placeholder='What needs to be done?' required><button type='submit'>Add</button></form><div id='filter-bar' class='filter-bar'><button class='filter-btn active' data-filter='all'>All</button><button class='filter-btn' data-filter='active'>Active</button><button class='filter-btn' data-filter='completed'>Completed</button></div><p id='task-count' class='task-count'>0 items left</p><ul id='task-list' class='task-list'></ul></div><script src='/static/app.js'></script></body></html>""",
            "static/app.js": """const API='/api/tasks';let currentFilter='all';const form=document.getElementById('task-form');const titleIn=document.getElementById('task-title');const listEl=document.getElementById('task-list');const countEl=document.getElementById('task-count');const filterBar=document.getElementById('filter-bar');async function fetchTasks(){const url=currentFilter==='all'?API:`${API}?status=${currentFilter}`;const res=await fetch(url);const tasks=await res.json();render(tasks)}function render(tasks){listEl.innerHTML='';tasks.forEach((t)=>{const li=document.createElement('li');li.className='task-item'+(t.completed?' completed':'');const cb=document.createElement('input');cb.type='checkbox';cb.checked=t.completed;cb.addEventListener('change',()=>toggleTask(t.id,!t.completed));const span=document.createElement('span');span.className='task-title';span.textContent=t.title;const del=document.createElement('button');del.className='delete-btn';del.textContent='×';del.addEventListener('click',()=>deleteTask(t.id));li.append(cb,span,del);listEl.appendChild(li)});updateCount()}async function updateCount(){const res=await fetch(API+'?status=active');const active=await res.json();countEl.textContent=`${active.length} item${active.length!==1?'s':''} left`}form.addEventListener('submit',async(e)=>{e.preventDefault();const title=titleIn.value.trim();if(!title)return;await fetch(API,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title})});titleIn.value='';fetchTasks()});async function toggleTask(id,completed){await fetch(`${API}/${id}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({completed})});fetchTasks()}async function deleteTask(id){await fetch(`${API}/${id}`,{method:'DELETE'});fetchTasks()}filterBar.addEventListener('click',(e)=>{if(!e.target.classList.contains('filter-btn'))return;currentFilter=e.target.dataset.filter;filterBar.querySelectorAll('.filter-btn').forEach((b)=>b.classList.remove('active'));e.target.classList.add('active');fetchTasks()});fetchTasks();""",
            "static/style.css": """*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}body{font-family:Arial,sans-serif;background:#f5f5f5;color:#333;display:flex;justify-content:center;padding:40px 16px}.container{width:100%;max-width:520px}h1{text-align:center;margin-bottom:24px;font-size:2rem;color:#b83f45}.task-input{display:flex;gap:8px;margin-bottom:16px}.task-input input{flex:1;padding:10px 14px;font-size:1rem;border:2px solid #ddd;border-radius:6px}.task-input button{padding:10px 20px;font-size:1rem;background:#b83f45;color:#fff;border:none;border-radius:6px}.filter-bar{display:flex;gap:8px;margin-bottom:8px}.filter-btn{flex:1;padding:8px;font-size:.9rem;background:#fff;border:2px solid #ddd;border-radius:6px}.filter-btn.active{background:#b83f45;color:#fff;border-color:#b83f45}.task-count{text-align:right;font-size:.85rem;color:#888;margin-bottom:12px}.task-list{list-style:none}.task-item{display:flex;align-items:center;gap:12px;padding:12px 14px;background:#fff;border-radius:6px;margin-bottom:8px;box-shadow:0 1px 3px rgba(0,0,0,.08)}.task-item.completed .task-title{text-decoration:line-through;color:#aaa}.delete-btn{background:none;border:none;font-size:1.2rem;color:#ccc;cursor:pointer}""",
            "README.md": """# Todo App\n\nLocal todo prototype built with Flask, SQLite, and a static frontend.\n\n## Run\n```bash\npython3 -m venv .venv\nsource .venv/bin/activate\npip install -r requirements.txt\npython app.py\n```\nOpen http://localhost:5000\n\n## Test\n```bash\nsource .venv/bin/activate\npytest tests -q\n```\n""",
            "tests/test_api.py": """import json\nimport os\nimport tempfile\n_tmp = tempfile.NamedTemporaryFile(suffix='.db', delete=False); _tmp.close(); os.environ['TODO_DB'] = _tmp.name\nfrom app import app\n\n\ndef test_todo_flow():\n    app.config['TESTING'] = True\n    with app.test_client() as c:\n        assert c.get('/health').status_code == 200\n        created = c.post('/api/tasks', data=json.dumps({'title': 'Buy milk'}), content_type='application/json')\n        assert created.status_code == 201\n        task_id = created.get_json()['id']\n        assert c.patch(f'/api/tasks/{task_id}', data=json.dumps({'completed': True}), content_type='application/json').status_code == 200\n        assert c.get('/api/tasks?status=completed').status_code == 200\n        assert c.delete(f'/api/tasks/{task_id}').status_code == 204\n""",
        }

    def _notes_files(self) -> dict[str, str]:
        return {
            "requirements.txt": self._shared_requirements(),
            "app.py": """import os\nimport sqlite3\nfrom flask import Flask, jsonify, render_template, request\n\napp = Flask(__name__)\nDATABASE = os.environ.get('NOTES_DB', 'notes.db')\n\n\ndef get_db():\n    conn = sqlite3.connect(DATABASE)\n    conn.row_factory = sqlite3.Row\n    return conn\n\n\ndef init_db():\n    conn = get_db()\n    conn.execute('CREATE TABLE IF NOT EXISTS notes (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, content TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)')\n    conn.commit(); conn.close()\n\nwith app.app_context():\n    init_db()\n\n@app.route('/')\ndef index():\n    return render_template('index.html')\n\n@app.route('/health')\ndef health():\n    return jsonify({'status': 'ok'})\n\n@app.route('/api/notes', methods=['GET'])\ndef list_notes():\n    q = request.args.get('q', '').strip()\n    conn = get_db()\n    if q:\n        rows = conn.execute('SELECT * FROM notes WHERE title LIKE ? OR content LIKE ? ORDER BY created_at DESC', (f'%{q}%', f'%{q}%')).fetchall()\n    else:\n        rows = conn.execute('SELECT * FROM notes ORDER BY created_at DESC').fetchall()\n    conn.close()\n    return jsonify([dict(r) for r in rows])\n\n@app.route('/api/notes', methods=['POST'])\ndef create_note():\n    data = request.get_json(silent=True) or {}\n    title = (data.get('title') or '').strip(); content = (data.get('content') or '').strip()\n    if not title or not content: return jsonify({'error': 'title and content are required'}), 400\n    conn = get_db(); cur = conn.execute('INSERT INTO notes (title, content) VALUES (?, ?)', (title, content)); conn.commit(); row = conn.execute('SELECT * FROM notes WHERE id = ?', (cur.lastrowid,)).fetchone(); conn.close()\n    return jsonify(dict(row)), 201\n\n@app.route('/api/notes/<int:note_id>', methods=['PATCH'])\ndef update_note(note_id):\n    data = request.get_json(silent=True) or {}\n    title = (data.get('title') or '').strip(); content = (data.get('content') or '').strip()\n    if not title or not content: return jsonify({'error': 'title and content are required'}), 400\n    conn = get_db(); row = conn.execute('SELECT * FROM notes WHERE id = ?', (note_id,)).fetchone()\n    if row is None: conn.close(); return jsonify({'error': 'note not found'}), 404\n    conn.execute('UPDATE notes SET title = ?, content = ? WHERE id = ?', (title, content, note_id)); conn.commit(); row = conn.execute('SELECT * FROM notes WHERE id = ?', (note_id,)).fetchone(); conn.close(); return jsonify(dict(row))\n\n@app.route('/api/notes/<int:note_id>', methods=['DELETE'])\ndef delete_note(note_id):\n    conn = get_db(); row = conn.execute('SELECT * FROM notes WHERE id = ?', (note_id,)).fetchone()\n    if row is None: conn.close(); return jsonify({'error': 'note not found'}), 404\n    conn.execute('DELETE FROM notes WHERE id = ?', (note_id,)); conn.commit(); conn.close(); return '', 204\n\nif __name__ == '__main__':\n    app.run(host='0.0.0.0', port=int(os.environ.get('PORT', '5000')), debug=False)\n""",
            "templates/index.html": """<!doctype html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Notes App</title><link rel='stylesheet' href='/static/style.css'></head><body><main class='container'><h1>Notes App</h1><section class='panel'><form id='note-form'><input id='note-title' placeholder='Note title' required><textarea id='note-content' placeholder='Write your note...' required></textarea><button type='submit'>Save Note</button></form></section><section class='panel'><div class='row'><input id='search' placeholder='Search notes'><button id='refresh'>Refresh</button></div><div id='notes'></div></section></main><script src='/static/app.js'></script></body></html>""",
            "static/app.js": """const $=(s)=>document.querySelector(s);async function loadNotes(){const q=$('#search').value.trim();const url=q?`/api/notes?q=${encodeURIComponent(q)}`:'/api/notes';const res=await fetch(url);const notes=await res.json();$('#notes').innerHTML=notes.map(n=>`<article class='note'><h3>${n.title}</h3><p>${n.content}</p><button data-id='${n.id}' class='delete-btn'>Delete</button></article>`).join('')||'<p class=\"empty\">No notes yet.</p>';}$('#note-form').addEventListener('submit',async(e)=>{e.preventDefault();await fetch('/api/notes',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title:$('#note-title').value.trim(),content:$('#note-content').value.trim()})});$('#note-title').value='';$('#note-content').value='';loadNotes();});$('#notes').addEventListener('click',async(e)=>{if(e.target.dataset.id){await fetch(`/api/notes/${e.target.dataset.id}`,{method:'DELETE'});loadNotes();}});$('#refresh').addEventListener('click',loadNotes);$('#search').addEventListener('keydown',(e)=>{if(e.key==='Enter')loadNotes()});loadNotes();""",
            "static/style.css": """body{font-family:Arial,sans-serif;background:#f8fafc;margin:0}.container{max-width:900px;margin:0 auto;padding:24px}.panel{background:#fff;border-radius:10px;padding:16px;margin-bottom:16px;box-shadow:0 1px 4px rgba(0,0,0,.08)}.row{display:flex;gap:8px;flex-wrap:wrap}input,textarea,button{font:inherit;padding:10px;border-radius:8px;border:1px solid #cbd5e1}input,textarea{width:100%}button{background:#0f766e;color:#fff;border:none;cursor:pointer}.note{border-top:1px solid #e2e8f0;padding:12px 0}.note h3{margin:0 0 6px}.delete-btn{background:#dc2626;margin-top:8px}.empty{color:#64748b}""",
            "README.md": """# Notes App\n\nLocal notes prototype built with Flask, SQLite, and a static frontend.\n\n## Run\n```bash\npython3 -m venv .venv\nsource .venv/bin/activate\npip install -r requirements.txt\npython app.py\n```\nOpen http://localhost:5000\n\n## Test\n```bash\nsource .venv/bin/activate\npytest tests -q\n```\n""",
            "tests/test_api.py": """import json\nimport os\nimport tempfile\n_tmp = tempfile.NamedTemporaryFile(suffix='.db', delete=False); _tmp.close(); os.environ['NOTES_DB'] = _tmp.name\nfrom app import app\n\n\ndef test_notes_flow():\n    app.config['TESTING'] = True\n    with app.test_client() as c:\n        assert c.get('/health').status_code == 200\n        created = c.post('/api/notes', data=json.dumps({'title': 'Idea', 'content': 'Build an app'}), content_type='application/json')\n        assert created.status_code == 201\n        note_id = created.get_json()['id']\n        assert c.get('/api/notes?q=Idea').status_code == 200\n        assert c.patch(f'/api/notes/{note_id}', data=json.dumps({'title': 'Idea updated', 'content': 'Ship it'}), content_type='application/json').status_code == 200\n        assert c.delete(f'/api/notes/{note_id}').status_code == 204\n""",
        }

    def _expense_files(self) -> dict[str, str]:
        return {
            "requirements.txt": self._shared_requirements(),
            "app.py": """import os\nimport sqlite3\nfrom flask import Flask, jsonify, render_template, request\n\napp = Flask(__name__)\nDATABASE = os.environ.get('EXPENSE_DB', 'expenses.db')\n\n\ndef get_db():\n    conn = sqlite3.connect(DATABASE)\n    conn.row_factory = sqlite3.Row\n    return conn\n\n\ndef init_db():\n    conn = get_db()\n    conn.execute('CREATE TABLE IF NOT EXISTS expenses (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, amount REAL NOT NULL, category TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)')\n    conn.commit(); conn.close()\n\nwith app.app_context():\n    init_db()\n\n@app.route('/')\ndef index(): return render_template('index.html')\n@app.route('/health')\ndef health(): return jsonify({'status':'ok'})\n@app.route('/api/expenses', methods=['GET'])\ndef list_expenses():\n    category = request.args.get('category', '').strip()\n    conn = get_db()\n    if category:\n        rows = conn.execute('SELECT * FROM expenses WHERE category = ? ORDER BY created_at DESC', (category,)).fetchall()\n    else:\n        rows = conn.execute('SELECT * FROM expenses ORDER BY created_at DESC').fetchall()\n    conn.close(); return jsonify([dict(r) for r in rows])\n@app.route('/api/expenses', methods=['POST'])\ndef create_expense():\n    data = request.get_json(silent=True) or {}\n    title=(data.get('title') or '').strip(); category=(data.get('category') or '').strip(); amount=data.get('amount')\n    if not title or not category or amount is None: return jsonify({'error':'title, category, and amount are required'}), 400\n    conn=get_db(); cur=conn.execute('INSERT INTO expenses (title, amount, category) VALUES (?, ?, ?)', (title, float(amount), category)); conn.commit(); row=conn.execute('SELECT * FROM expenses WHERE id = ?', (cur.lastrowid,)).fetchone(); conn.close(); return jsonify(dict(row)), 201\nif __name__ == '__main__': app.run(host='0.0.0.0', port=int(os.environ.get('PORT', '5000')), debug=False)\n""",
            "templates/index.html": """<!doctype html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Expense Tracker</title><link rel='stylesheet' href='/static/style.css'></head><body><main class='container'><h1>Expense Tracker</h1><section class='panel'><form id='expense-form'><input id='title' placeholder='Expense title' required><input id='amount' type='number' step='0.01' placeholder='Amount' required><input id='category' placeholder='Category' required><button type='submit'>Add Expense</button></form></section><section class='panel'><div class='row'><input id='filter-category' placeholder='Filter by category'><button id='refresh'>Refresh</button></div><div id='expenses'></div></section></main><script src='/static/app.js'></script></body></html>""",
            "static/app.js": """const $=(s)=>document.querySelector(s);async function loadExpenses(){const category=$('#filter-category').value.trim();const url=category?`/api/expenses?category=${encodeURIComponent(category)}`:'/api/expenses';const res=await fetch(url);const items=await res.json();$('#expenses').innerHTML=items.map(x=>`<article class='row-item'><strong>${x.title}</strong><span>$${Number(x.amount).toFixed(2)}</span><span>${x.category}</span></article>`).join('')||'<p class=\"empty\">No expenses yet.</p>';}$('#expense-form').addEventListener('submit',async(e)=>{e.preventDefault();await fetch('/api/expenses',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title:$('#title').value.trim(),amount:$('#amount').value,category:$('#category').value.trim()})});$('#title').value='';$('#amount').value='';$('#category').value='';loadExpenses();});$('#refresh').addEventListener('click',loadExpenses);$('#filter-category').addEventListener('keydown',(e)=>{if(e.key==='Enter')loadExpenses()});loadExpenses();""",
            "static/style.css": """body{font-family:Arial,sans-serif;background:#f8fafc;margin:0}.container{max-width:900px;margin:0 auto;padding:24px}.panel{background:#fff;border-radius:10px;padding:16px;margin-bottom:16px;box-shadow:0 1px 4px rgba(0,0,0,.08)}.row{display:flex;gap:8px;flex-wrap:wrap}input,button{font:inherit;padding:10px;border-radius:8px;border:1px solid #cbd5e1}input{width:100%}button{background:#2563eb;color:#fff;border:none;cursor:pointer}.row-item{display:flex;gap:12px;border-top:1px solid #e5e7eb;padding:12px 0}.empty{color:#64748b}""",
            "README.md": """# Expense Tracker\n\nLocal expense tracker built with Flask and SQLite.\n\n## Run\n```bash\npython3 -m venv .venv\nsource .venv/bin/activate\npip install -r requirements.txt\npython app.py\n```\nOpen http://localhost:5000\n""",
            "tests/test_api.py": """import json\nimport os\nimport tempfile\n_tmp = tempfile.NamedTemporaryFile(suffix='.db', delete=False); _tmp.close(); os.environ['EXPENSE_DB'] = _tmp.name\nfrom app import app\n\n\ndef test_expense_flow():\n    app.config['TESTING'] = True\n    with app.test_client() as c:\n        assert c.get('/health').status_code == 200\n        created = c.post('/api/expenses', data=json.dumps({'title':'Coffee','amount':4.5,'category':'Food'}), content_type='application/json')\n        assert created.status_code == 201\n        assert c.get('/api/expenses?category=Food').status_code == 200\n""",
        }

    def _bookmark_files(self) -> dict[str, str]:
        return {
            "requirements.txt": self._shared_requirements(),
            "app.py": """import os\nimport sqlite3\nfrom flask import Flask, jsonify, render_template, request\n\napp = Flask(__name__)\nDATABASE = os.environ.get('BOOKMARK_DB', 'bookmarks.db')\n\n\ndef get_db():\n    conn = sqlite3.connect(DATABASE)\n    conn.row_factory = sqlite3.Row\n    return conn\n\n\ndef init_db():\n    conn = get_db(); conn.execute('CREATE TABLE IF NOT EXISTS bookmarks (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, url TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)'); conn.commit(); conn.close()\nwith app.app_context(): init_db()\n@app.route('/')\ndef index(): return render_template('index.html')\n@app.route('/health')\ndef health(): return jsonify({'status':'ok'})\n@app.route('/api/bookmarks', methods=['GET'])\ndef list_bookmarks():\n    q=request.args.get('q','').strip(); conn=get_db();\n    if q: rows=conn.execute('SELECT * FROM bookmarks WHERE title LIKE ? OR url LIKE ? ORDER BY created_at DESC',(f'%{q}%',f'%{q}%')).fetchall()\n    else: rows=conn.execute('SELECT * FROM bookmarks ORDER BY created_at DESC').fetchall()\n    conn.close(); return jsonify([dict(r) for r in rows])\n@app.route('/api/bookmarks', methods=['POST'])\ndef create_bookmark():\n    data=request.get_json(silent=True) or {}; title=(data.get('title') or '').strip(); url=(data.get('url') or '').strip()\n    if not title or not url: return jsonify({'error':'title and url are required'}), 400\n    conn=get_db(); cur=conn.execute('INSERT INTO bookmarks (title, url) VALUES (?, ?)', (title, url)); conn.commit(); row=conn.execute('SELECT * FROM bookmarks WHERE id = ?', (cur.lastrowid,)).fetchone(); conn.close(); return jsonify(dict(row)), 201\nif __name__ == '__main__': app.run(host='0.0.0.0', port=int(os.environ.get('PORT', '5000')), debug=False)\n""",
            "templates/index.html": """<!doctype html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Bookmark Manager</title><link rel='stylesheet' href='/static/style.css'></head><body><main class='container'><h1>Bookmark Manager</h1><section class='panel'><form id='bookmark-form'><input id='title' placeholder='Title' required><input id='url' placeholder='https://example.com' required><button type='submit'>Add Bookmark</button></form></section><section class='panel'><div class='row'><input id='search' placeholder='Search title or URL'><button id='refresh'>Refresh</button></div><div id='bookmarks'></div></section></main><script src='/static/app.js'></script></body></html>""",
            "static/app.js": """const $=(s)=>document.querySelector(s);async function loadBookmarks(){const q=$('#search').value.trim();const url=q?`/api/bookmarks?q=${encodeURIComponent(q)}`:'/api/bookmarks';const res=await fetch(url);const items=await res.json();$('#bookmarks').innerHTML=items.map(x=>`<article class='row-item'><strong>${x.title}</strong><a href='${x.url}' target='_blank' rel='noreferrer'>${x.url}</a></article>`).join('')||'<p class=\"empty\">No bookmarks yet.</p>';}$('#bookmark-form').addEventListener('submit',async(e)=>{e.preventDefault();await fetch('/api/bookmarks',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title:$('#title').value.trim(),url:$('#url').value.trim()})});$('#title').value='';$('#url').value='';loadBookmarks();});$('#refresh').addEventListener('click',loadBookmarks);$('#search').addEventListener('keydown',(e)=>{if(e.key==='Enter')loadBookmarks()});loadBookmarks();""",
            "static/style.css": """body{font-family:Arial,sans-serif;background:#f8fafc;margin:0}.container{max-width:900px;margin:0 auto;padding:24px}.panel{background:#fff;border-radius:10px;padding:16px;margin-bottom:16px;box-shadow:0 1px 4px rgba(0,0,0,.08)}.row{display:flex;gap:8px;flex-wrap:wrap}input,button{font:inherit;padding:10px;border-radius:8px;border:1px solid #cbd5e1}input{width:100%}button{background:#2563eb;color:#fff;border:none;cursor:pointer}.row-item{display:flex;flex-direction:column;gap:6px;border-top:1px solid #e5e7eb;padding:12px 0}.empty{color:#64748b}a{color:#1d4ed8}""",
            "README.md": """# Bookmark Manager\n\nLocal bookmark manager built with Flask and SQLite.\n\n## Run\n```bash\npython3 -m venv .venv\nsource .venv/bin/activate\npip install -r requirements.txt\npython app.py\n```\nOpen http://localhost:5000\n""",
            "tests/test_api.py": """import json\nimport os\nimport tempfile\n_tmp = tempfile.NamedTemporaryFile(suffix='.db', delete=False); _tmp.close(); os.environ['BOOKMARK_DB'] = _tmp.name\nfrom app import app\n\n\ndef test_bookmark_flow():\n    app.config['TESTING'] = True\n    with app.test_client() as c:\n        assert c.get('/health').status_code == 200\n        created = c.post('/api/bookmarks', data=json.dumps({'title':'OpenAI','url':'https://openai.com'}), content_type='application/json')\n        assert created.status_code == 201\n        assert c.get('/api/bookmarks?q=OpenAI').status_code == 200\n""",
        }

    def _inventory_files(self) -> dict[str, str]:
        return {
            "requirements.txt": self._shared_requirements(),
            "app.py": """import os\nimport sqlite3\nfrom flask import Flask, jsonify, render_template, request\n\napp = Flask(__name__)\nDATABASE = os.environ.get('INVENTORY_DB', 'inventory.db')\n\n\ndef get_db():\n    conn = sqlite3.connect(DATABASE)\n    conn.row_factory = sqlite3.Row\n    return conn\n\n\ndef init_db():\n    conn = get_db(); conn.execute('CREATE TABLE IF NOT EXISTS items (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL, quantity INTEGER NOT NULL, status TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)'); conn.commit(); conn.close()\nwith app.app_context(): init_db()\n@app.route('/')\ndef index(): return render_template('index.html')\n@app.route('/health')\ndef health(): return jsonify({'status':'ok'})\n@app.route('/api/items', methods=['GET'])\ndef list_items():\n    status=request.args.get('status','').strip(); conn=get_db();\n    if status: rows=conn.execute('SELECT * FROM items WHERE status = ? ORDER BY created_at DESC',(status,)).fetchall()\n    else: rows=conn.execute('SELECT * FROM items ORDER BY created_at DESC').fetchall()\n    conn.close(); return jsonify([dict(r) for r in rows])\n@app.route('/api/items', methods=['POST'])\ndef create_item():\n    data=request.get_json(silent=True) or {}; name=(data.get('name') or '').strip(); status=(data.get('status') or '').strip(); quantity=data.get('quantity')\n    if not name or not status or quantity is None: return jsonify({'error':'name, quantity, and status are required'}), 400\n    conn=get_db(); cur=conn.execute('INSERT INTO items (name, quantity, status) VALUES (?, ?, ?)', (name, int(quantity), status)); conn.commit(); row=conn.execute('SELECT * FROM items WHERE id = ?', (cur.lastrowid,)).fetchone(); conn.close(); return jsonify(dict(row)), 201\nif __name__ == '__main__': app.run(host='0.0.0.0', port=int(os.environ.get('PORT', '5000')), debug=False)\n""",
            "templates/index.html": """<!doctype html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Inventory Tracker</title><link rel='stylesheet' href='/static/style.css'></head><body><main class='container'><h1>Inventory Tracker</h1><section class='panel'><form id='item-form'><input id='name' placeholder='Item name' required><input id='quantity' type='number' placeholder='Quantity' required><input id='status' placeholder='Status (in-stock/backorder)' required><button type='submit'>Add Item</button></form></section><section class='panel'><div class='row'><input id='filter-status' placeholder='Filter by status'><button id='refresh'>Refresh</button></div><div id='items'></div></section></main><script src='/static/app.js'></script></body></html>""",
            "static/app.js": """const $=(s)=>document.querySelector(s);async function loadItems(){const status=$('#filter-status').value.trim();const url=status?`/api/items?status=${encodeURIComponent(status)}`:'/api/items';const res=await fetch(url);const items=await res.json();$('#items').innerHTML=items.map(x=>`<article class='row-item'><strong>${x.name}</strong><span>Qty: ${x.quantity}</span><span>Status: ${x.status}</span></article>`).join('')||'<p class=\"empty\">No inventory yet.</p>';}$('#item-form').addEventListener('submit',async(e)=>{e.preventDefault();await fetch('/api/items',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name:$('#name').value.trim(),quantity:$('#quantity').value,status:$('#status').value.trim()})});$('#name').value='';$('#quantity').value='';$('#status').value='';loadItems();});$('#refresh').addEventListener('click',loadItems);$('#filter-status').addEventListener('keydown',(e)=>{if(e.key==='Enter')loadItems()});loadItems();""",
            "static/style.css": """body{font-family:Arial,sans-serif;background:#f8fafc;margin:0}.container{max-width:900px;margin:0 auto;padding:24px}.panel{background:#fff;border-radius:10px;padding:16px;margin-bottom:16px;box-shadow:0 1px 4px rgba(0,0,0,.08)}.row{display:flex;gap:8px;flex-wrap:wrap}input,button{font:inherit;padding:10px;border-radius:8px;border:1px solid #cbd5e1}input{width:100%}button{background:#2563eb;color:#fff;border:none;cursor:pointer}.row-item{display:flex;gap:12px;border-top:1px solid #e5e7eb;padding:12px 0}.empty{color:#64748b}""",
            "README.md": """# Inventory Tracker\n\nLocal inventory tracker built with Flask and SQLite.\n\n## Run\n```bash\npython3 -m venv .venv\nsource .venv/bin/activate\npip install -r requirements.txt\npython app.py\n```\nOpen http://localhost:5000\n""",
            "tests/test_api.py": """import json\nimport os\nimport tempfile\n_tmp = tempfile.NamedTemporaryFile(suffix='.db', delete=False); _tmp.close(); os.environ['INVENTORY_DB'] = _tmp.name\nfrom app import app\n\n\ndef test_inventory_flow():\n    app.config['TESTING'] = True\n    with app.test_client() as c:\n        assert c.get('/health').status_code == 200\n        created = c.post('/api/items', data=json.dumps({'name':'Mouse','quantity':5,'status':'in-stock'}), content_type='application/json')\n        assert created.status_code == 201\n        assert c.get('/api/items?status=in-stock').status_code == 200\n""",
        }
